# Example
```rust
# use nom::bits::complete::bool;
# use nom::IResult;
# use nom::error::{Error, ErrorKind};

fn parse(input: (&[u8], usize)) -> IResult<(&[u8], usize), bool> {
bool(input)
}

assert_eq!(parse(([0b10000000].as_ref(), 0)), Ok((([0b10000000].as_ref(), 1), true)));
